try { var data = JSON.parse(msg);
var lines = [];
lines.push('# ' + (data.title || 'Meeting Minutes'));
lines.push('');
lines.push('**Date:** ' + (data.date || 'N/A'));
lines.push('**Attendees:** ' + (data.attendees || []).join(', '));
lines.push('');
if (data.agenda_items && data.agenda_items.length > 0) {
  lines.push('## Agenda');
  data.agenda_items.forEach(function(item) { lines.push('- ' + item); });
  lines.push('');
}
if (data.decisions && data.decisions.length > 0) {
  lines.push('## Decisions');
  data.decisions.forEach(function(d) { lines.push('- ' + d); });
  lines.push('');
}
if (data.action_items && data.action_items.length > 0) {
  lines.push('## Action Items');
  lines.push('| Assignee | Task | Deadline |');
  lines.push('|----------|------|----------|');
  data.action_items.forEach(function(a) {
    lines.push('| ' + (a.assignee||'TBD') + ' | ' + a.task + ' | ' + (a.deadline||'TBD') + ' |');
  });
  lines.push('');
}
if (data.key_discussion_points && data.key_discussion_points.length > 0) {
  lines.push('## Key Discussion Points');
  data.key_discussion_points.forEach(function(p) { lines.push('- ' + p); });
}
msg = lines.join('\n');
